import { forwardRef } from "react";
import type { HTMLAttributes, ReactNode } from "react";
import * as styles from "./Icon.css";
import type { IconSize } from "./Icon.config";
import { DEFAULT_ICON_SIZE, IconInnerSizeMap } from "./Icon.config";
import { clsx } from "clsx";
import { _BaseIcon } from "./_BaseIcon";

export interface IconProps extends HTMLAttributes<HTMLSpanElement> {
  /**
   * The icon content (typically an SVG element)
   */
  children: ReactNode;

  /**
   * The size of the icon container in pixels.
   * The inner icon (SVG) size is automatically determined based on the design system mapping:
   * - 12px container → 10px icon
   * - 16px container → 12px icon
   * - 20px container → 16px icon
   * - 24px container → 20px icon
   * - 32px container → 24px icon
   * @default 16
   */
  size?: IconSize;
}

export const Icon = forwardRef<HTMLSpanElement, IconProps>(
  ({ children, size = DEFAULT_ICON_SIZE, className, ...props }, ref) => {
    const iconClasses = clsx(styles.icon({ size }), className);
    const innerSize = IconInnerSizeMap[size];

    return (
      <span ref={ref} className={iconClasses} {...props}>
        <_BaseIcon size={innerSize}>{children}</_BaseIcon>
      </span>
    );
  }
);

Icon.displayName = "Icon";
